const topics = [
  'AI breakthroughs, agent releases, and model updates',
  'US and global economics: Fed, markets, tariffs, macro signals',
  'Solopreneur and creator economy trends',
  'Africa tech: startups, investment, infrastructure, fintech',
  'Business strategy and consulting trends',
  'Consulting and professional services market shifts',
  'Automation, no-code, and AI tool releases',
  'Emerging markets and investment flows'
];

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

return [{
  json: {
    task: `Daily news brief for ${today}. Cover all 8 Catalyst Works topics: ${topics.join('; ')}. For each topic find the 1-2 most important stories from the last 48 hours. Include full Catalyst Works impact analysis on every story (client acquisition, AI tool opportunity, business strategy lenses). End with a single This Week Signal sentence.`,
    from_number: 'n8n-scheduler',
    session_key: 'daily_news_brief',
    today
  }
}];

const result = $input.first().json.body.result || '';

// Extract the DELIVERABLE block from the QA output format
const deliverableMatch = result.match(/DELIVERABLE:\s*([\s\S]+)$/i);
const brief = deliverableMatch ? deliverableMatch[1].trim() : result.trim();

// Telegram has a 4096 char limit per message — split if needed
const MAX_LEN = 4000;
const chunks = [];

if (brief.length <= MAX_LEN) {
  chunks.push(brief);
} else {
  // Split on double newlines (section boundaries) to keep stories intact
  const sections = brief.split(/\n---\n/);
  let current = '';
  for (const section of sections) {
    if ((current + section).length > MAX_LEN) {
      if (current) chunks.push(current.trim());
      current = section;
    } else {
      current += (current ? '\n---\n' : '') + section;
    }
  }
  if (current) chunks.push(current.trim());
}

return chunks.map((chunk, i) => ({
  json: {
    chunk,
    part: i + 1,
    total: chunks.length,
    is_first: i === 0
  }
}));

const error = $input.first().json;
const msg = error?.body?.detail || error?.message || JSON.stringify(error).slice(0, 300);
return [{ json: { error_message: msg } }];
